const aiOutput = $input.first().json.output || '';

const match = aiOutput.match(/\[CHARTS_JSON\]([\s\S]*?)\[\/CHARTS_JSON\]/);
if (!match) {
  return [{ json: { error: 'No CHARTS_JSON block found', rawOutput: aiOutput.slice(-1200) } }];
}

let raw = match[1].trim();
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();

let charts;
try {
  charts = JSON.parse(raw);
} catch (e) {
  const repaired = raw.replace(/,\s*([\]\}])/g, '$1');
  try {
    charts = JSON.parse(repaired);
  } catch (e2) {
    return [{ json: { error: 'Failed to parse CHARTS_JSON: ' + e2.message, rawJson: raw.slice(0, 1200) } }];
  }
}

if (!Array.isArray(charts) || charts.length === 0) {
  return [{ json: { error: 'CHARTS_JSON is empty or not an array' } }];
}

return charts
  .filter(c => c && c.chartConfig && c.chartConfig.data)
  .map(c => ({ json: { sheetName: c.sheetName || 'chart', chartConfig: c.chartConfig } }));

// Code node runs ONCE for all items — iterate with .map()
const allItems  = $input.all();
const allCharts = $('Parse AI Chart Configs1').all();

return allItems.map((item, idx) => {
  const sheetName = allCharts[idx]?.json?.sheetName || ('chart_' + idx);
  return { json: { sheetName }, binary: item.binary };
});

// Sanitize Chart.js config before sending to QuickChart
// Removes JS function strings and fixes common issues that cause 400 errors
const item = $input.first();
const config = item.json.chartConfig;

function sanitize(obj) {
  if (obj === null || obj === undefined) return obj;
  if (Array.isArray(obj)) return obj.map(sanitize);
  if (typeof obj === 'object') {
    const out = {};
    for (const [k, v] of Object.entries(obj)) {
      // Remove keys whose value is a JS function string
      if (typeof v === 'string' && /^\s*function\s*\(/.test(v)) continue;
      if (typeof v === 'string' && /^\s*\(.*\)\s*=>/.test(v)) continue;
      out[k] = sanitize(v);
    }
    return out;
  }
  // Replace non-finite numbers with null
  if (typeof obj === 'number' && !isFinite(obj)) return null;
  return obj;
}

const sanitized = sanitize(config);

return [{ json: { sheetName: item.json.sheetName, chartConfig: sanitized } }];
